  distributeMetrics(metrics) {
    // Share metrics with optimization bot
    if (this.bots.optimization.isRunning) {
      try {
        this.bots.optimization.processMetrics?.(metrics);
      } catch (error) {
        // Ignore if method doesn't exist
      }
    }
    
    // Emit metrics for external listeners
    this.emit('metrics', metrics);
  }

  updateStatus() {
    let activeCount = 0;
    
    for (const bot of Object.values(this.bots)) {
      if (bot.isRunning) {
        activeCount++;
      }
    }
    
    this.status.active = activeCount;
    this.status.lastUpdate = new Date();
    
    this.emit('statusUpdate', this.status);
  }

  // Public API methods
  getBotStatus(botName) {
    const bot = this.bots[botName];
    if (!bot) return null;
    
    return {
      name: botName,
      isRunning: bot.isRunning,
      status: bot.getBotStatus ? bot.getBotStatus() : 'unknown'
    };
  }

  getAllBotStatuses() {
    const statuses = {};
    
    for (const [name, bot] of Object.entries(this.bots)) {
      statuses[name] = this.getBotStatus(name);
    }
    
    return {
      manager: {
        name: this.name,
        isRunning: this.isRunning,
        status: this.status
      },
      bots: statuses
    };
  }

  async restartBotByName(botName) {
    if (!this.bots[botName]) {
      throw new Error(`Bot '${botName}' not found`);
    }
    
    await this.restartBot(botName);
  }

  async stopBotByName(botName) {
    const bot = this.bots[botName];
    if (!bot) {
      throw new Error(`Bot '${botName}' not found`);
    }
    
    await bot.stop();
    this.updateStatus();
  }

  async startBotByName(botName) {
    const bot = this.bots[botName];
    if (!bot) {
      throw new Error(`Bot '${botName}' not found`);
    }
    
    await bot.start();
    this.updateStatus();
  }

